#include <ctype.h>
#include <stdio.h>

int main(void) {
    int ch = getchar();
    if (ch == EOF) return 1;
    unsigned char value = (unsigned char)ch;
    if (isdigit(value)) puts("digit");
    else if (isalpha(value)) puts("alpha");
    else puts("other");
    return 0;
}
